let newPosX = 0, newPosY = 0, startPosX = 0, startPosY = 0;

// when the user clicks down on the element
el.addEventListener('mousedown', function(e){
    e.preventDefault();
    
    // get the starting position of the cursor
    startPosX = e.clientX;
    startPosY = e.clientY;
    
    document.addEventListener('mousemove', mouseMove);
    
    document.addEventListener('mouseup', function(){
        document.removeEventListener('mousemove', mouseMove);
    });
    
});


function mouseMove(e) {
    // calculate the new position
    newPosX = startPosX - e.clientX;
    newPosY = startPosY - e.clientY;

    // with each move we also want to update the start X and Y
    startPosX = e.clientX;
    startPosY = e.clientY;

    // set the element's new position:
    el.style.top = ((el.offsetTop - newPosY) > 0) ? (((el.offsetTop - newPosY) > (el.parentElement.offsetHeight - el.getBoundingClientRect().height)) ? el.parentElement.offsetHeight - el.getBoundingClientRect().height:(el.offsetTop - newPosY)) + "px":"0px";
    el.style.left = ((el.offsetLeft - newPosX) > 0) ? (((el.offsetLeft - newPosX) > (el.parentElement.offsetWidth - el.offsetWidth)) ? (el.parentElement.offsetWidth - el.offsetWidth):(el.offsetLeft - newPosX)) + "px":"0px";
    if(((el.offsetTop - newPosY) < 0) || ((el.offsetLeft - newPosX) < 0))
      document.removeEventListener('mousemove', mouseMove);
}

